document.addEventListener("DOMContentLoaded",(()=>{const e=document.querySelector(".nav-toggle"),t=document.getElementById("site-nav-panel");if(!e||!t)return;const n=()=>{document.body.classList.remove("nav-open"),e.setAttribute("aria-expanded","false"),t.setAttribute("aria-hidden","true")};e.addEventListener("click",(()=>{document.body.classList.contains("nav-open")?n():(document.body.classList.add("nav-open"),e.setAttribute("aria-expanded","true"),t.setAttribute("aria-hidden","false"))})),t.addEventListener("click",(e=>{e.target.closest("a")&&n()})),document.addEventListener("keydown",(e=>{"Escape"===e.key&&n()}))}));